218	func uniqueRepos(runners []config.RunnerConfig) []string {
219		seen := make(map[string]struct{})
220		for _, rc := range runners {
221			if rc.Repo != "" {
222				seen[rc.Repo] = struct{}{}
223			}
224		}
225		out := make([]string, 0, len(seen))
226		for repo := range seen {
227			out = append(out, repo)
228		}
229		sort.Strings(out)
230		return out
231	}
232	
233	func uniqueOrgs(runners []config.RunnerConfig) []string {
234		seen := make(map[string]struct{})
235		for _, rc := range runners {
236			if rc.Org != "" {
237				seen[rc.Org] = struct{}{}
238			}
239		}
240		out := make([]string, 0, len(seen))
241		for org := range seen {
242			out = append(out, org)
243		}
244		sort.Strings(out)
245		return out
246	}
247	
248	func uniqueHostNames(runners []config.RunnerConfig) []string {
249		seen := make(map[string]struct{})
250		for _, rc := range runners {
251			seen[rc.Host] = struct{}{}
252		}
253		out := make([]string, 0, len(seen))
254		for name := range seen {
255			out = append(out, name)
256		}
257		sort.Strings(out)
258		return out
259	}
260	
261	func modesForHost(runners []config.RunnerConfig, hostName, hostOS string) map[string]bool {
262		m := make(map[string]bool)
263		for _, rc := range runners {
264			if rc.Host != hostName {
265				continue
266			}
267			m[rc.EffectiveMode(hostOS)] = true
268		}
269		return m
270	}
