272	// checkAgenticWorkflowDockerHint warns when docker-mode runners use the default bridge network,
273	// which breaks GitHub Agentic Workflows MCP gateway localhost health checks unless gh-aw is fixed upstream.
274	func checkAgenticWorkflowDockerHint(w io.Writer, hostName string, hostOS string, runners []config.RunnerConfig, r *Result) {
275		var names []string
276		for _, rc := range runners {
277			if rc.Host != hostName {
278				continue
279			}
280			if rc.EffectiveMode(hostOS) != "docker" {
281				continue
282			}
283			if rc.EffectiveDockerNetworkMode(hostOS) != "bridge" {
284				continue
285			}
286			names = append(names, rc.Name)
287		}
288		if len(names) == 0 {
289			return
290		}
291		sort.Strings(names)
292		printLine(w, sevWarn, hostName, fmt.Sprintf(
293			"agentic workflows: bridge-network docker runners (%s) may fail MCP gateway health checks; set docker_network_mode: host or use mode: native — see host setup documentation",
294			strings.Join(names, ", "),
295		))
296		r.Warn++
297	}
