299	func checkDocker(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
300		if h.OS == "windows" {
301			out, err := h.RunShell(`docker info --format "{{.ServerVersion}}"`)
302			out = strings.TrimSpace(out)
303			if err != nil || out == "" {
304				reason := "docker info did not return a server version"
305				if err != nil {
306					reason = err.Error()
307				}
308				printLine(w, sevFail, hostName, fmt.Sprintf("docker: daemon/CLI not usable (%s); install and start Docker (see README \"Host setup\")", reason))
309				r.Fail++
310				return
311			}
312			printLine(w, sevOK, hostName, fmt.Sprintf("docker: server version %s (image %s)", out, runner.RunnerDockerImage))
313			checkWindowsDockerSocket(w, hostName, h, runners, r)
314			return
315		}
316	
317		ok, err := runner.UnixDockerCLIInstalled(h)
318		if err != nil {
319			printLine(w, sevFail, hostName, fmt.Sprintf("docker: could not check CLI: %v", err))
320			r.Fail++
321			return
322		}
323		if !ok {
324			printLine(w, sevFail, hostName, "docker: CLI not on PATH; install Docker (see README \"Host setup\")")
325			r.Fail++
326			return
327		}
328		out, verr := runner.UnixDockerServerVersion(h)
329		if verr != nil {
330			printLine(w, sevFail, hostName, fmt.Sprintf("docker: %v", verr))
331			r.Fail++
332			return
333		}
334		printLine(w, sevOK, hostName, fmt.Sprintf("docker: server version %s (image %s)", out, runner.RunnerDockerImage))
335	
336		if h.OS == "linux" || h.OS == "darwin" {
337			checkUnixDockerSocket(w, hostName, h, runners, r)
338		}
339	}
