341	// checkWindowsDockerSocket probes the Docker Desktop socket GID and checks that any running
342	// docker-mode runner containers have the correct --group-add flag for it.
343	func checkWindowsDockerSocket(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
344		probeCmd := runner.DockerWindowsSockGIDProbeCommand(runner.RunnerDockerImage) + ` 2>$null`
345		out, err := h.RunShell(probeCmd)
346		if err != nil {
347			printLine(w, sevWarn, hostName, fmt.Sprintf(
348				"docker: could not probe socket GID; bind-mount may lack --group-add; jobs may fail with permission denied; recreate containers after fixing",
349			))
350			r.Warn++
351			return
352		}
353		gid := strings.TrimSpace(out)
354		printLine(w, sevOK, hostName, fmt.Sprintf("docker: socket GID=%s", gid))
355	
356		// Check each docker-mode runner container that is already running.
357		for _, rc := range runners {
358			if rc.Host != hostName || rc.EffectiveMode(h.OS) != "docker" {
359				continue
360			}
361			for _, inst := range rc.InstanceNames() {
362				cname := runner.ContainerName(inst)
363				running, rerr := h.RunShell(fmt.Sprintf(`docker inspect -f "{{.State.Running}}" %s 2>$null`, cname))
364				if rerr != nil || strings.TrimSpace(running) != "true" {
365					continue
366				}
367				// Get the supplemental groups the container was started with.
368				groups, gerr := h.RunShell(fmt.Sprintf(`docker inspect -f "{{.HostConfig.Groups}}" %s 2>$null`, cname))
369				groups = strings.TrimSpace(groups)
370				if gerr != nil || groups == "" || groups == "[]" {
371					printLine(w, sevFail, hostName, fmt.Sprintf(
372						"docker: container %s has no --group-add for socket GID %s; jobs will fail with permission denied; fix with: gh sr down %s && gh sr up %s",
373						cname, gid, rc.Name, rc.Name,
374					))
375					r.Fail++
376					continue
377				}
378				// groups is like "[999]" or "[0 999]"; check if socket GID is present.
379				if !strings.Contains(groups, gid) {
380					printLine(w, sevFail, hostName, fmt.Sprintf(
381						"docker: container %s groups=%s, socket GID=%s not included; jobs will fail with permission denied; fix with: gh sr down %s && gh sr up %s",
382						cname, groups, gid, rc.Name, rc.Name,
383					))
384					r.Fail++
385				} else {
386					printLine(w, sevOK, hostName, fmt.Sprintf("docker: container %s has socket GID %s in groups %s", cname, gid, groups))
387				}
388			}
389		}
390	}
