392	// checkUnixDockerSocket verifies the Docker socket path on Linux/macOS hosts and, if any docker-mode
393	// runner container is already running, checks that the socket is accessible inside it.
394	func checkUnixDockerSocket(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
395		socketPath, err := runner.EffectiveDockerSocket(h)
396		if err != nil {
397			printLine(w, sevFail, hostName, fmt.Sprintf("docker: %v", err))
398			r.Fail++
399			return
400		}
401		printLine(w, sevOK, hostName, fmt.Sprintf("docker: socket present at %s", socketPath))
402	
403		// For each docker-mode runner container that is already running, verify the socket is
404		// accessible inside it (catches containers started without the mount or without --group-add).
405		for _, rc := range runners {
406			if rc.Host != hostName || rc.EffectiveMode(h.OS) != "docker" {
407				continue
408			}
409			for _, inst := range rc.InstanceNames() {
410				cname := runner.ContainerName(inst)
411				running, rerr := h.Run(fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname))
412				if rerr != nil || strings.TrimSpace(running) != "true" {
413					continue
414				}
415				// Container is running; check that the socket is accessible inside.
416				res, execErr := h.Run(fmt.Sprintf("docker exec %s test -S /var/run/docker.sock && echo ok || echo missing", cname))
417				if execErr != nil || strings.TrimSpace(res) != "ok" {
418					printLine(w, sevWarn, hostName, fmt.Sprintf(
419						"docker: container %s is running but /var/run/docker.sock is not accessible inside it; recreate with: gh sr down %s && gh sr up %s",
420						cname, rc.Name, rc.Name,
421					))
422					r.Warn++
423				} else {
424					printLine(w, sevOK, hostName, fmt.Sprintf("docker: container %s has /var/run/docker.sock accessible", cname))
425				}
426			}
427		}
428	}
