430	// nativeInstallTargetsForHost lists (instanceName, runnerConfigName) for native-mode runners on hostName.
431	func nativeInstallTargetsForHost(runners []config.RunnerConfig, hostName, hostOS string) [][2]string {
432		var out [][2]string
433		for _, rc := range runners {
434			if rc.Host != hostName || rc.EffectiveMode(hostOS) != "native" {
435				continue
436			}
437			for _, inst := range rc.InstanceNames() {
438				out = append(out, [2]string{inst, rc.Name})
439			}
440		}
441		return out
442	}
443	
444	func checkNativeRunnerInstall(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
445		for _, pair := range nativeInstallTargetsForHost(runners, hostName, h.OS) {
446			inst, runnerName := pair[0], pair[1]
447			dir := h.RunnerDir(inst)
448			ok, err := runner.NativeRunnerConfigPresent(h, inst)
449			if err != nil {
450				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s: %v", inst, err))
451				r.Fail++
452				continue
453			}
454			if !ok {
455				printLine(w, sevFail, hostName, fmt.Sprintf("native: instance %s not installed (missing .runner under %s); run: gh sr setup %s", inst, dir, runnerName))
456				r.Fail++
457				continue
458			}
459			printLine(w, sevOK, hostName, fmt.Sprintf("native: instance %s installed", inst))
460		}
461	}
