463	func checkNative(w io.Writer, hostName string, h *host.Host, r *Result) {
464		switch h.OS {
465		case "linux":
466			out, err := h.Run(`if command -v curl >/dev/null 2>&1 && command -v tar >/dev/null 2>&1; then echo ok; else echo missing; fi`)
467			out = strings.TrimSpace(out)
468			if err != nil || out != "ok" {
469				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl and tar on PATH (%v)", err))
470				r.Fail++
471				return
472			}
473			printLine(w, sevOK, hostName, "native: curl and tar present")
474		case "darwin":
475			out, err := h.Run(`command -v curl >/dev/null 2>&1 && echo ok || echo missing`)
476			out = strings.TrimSpace(out)
477			if err != nil || out != "ok" {
478				printLine(w, sevFail, hostName, fmt.Sprintf("native: need curl (%v)", err))
479				r.Fail++
480				return
481			}
482			printLine(w, sevOK, hostName, "native: curl present")
483		case "windows":
484			out, err := h.RunShell(`$PSVersionTable.PSVersion.ToString()`)
485			out = strings.TrimSpace(out)
486			if err != nil || out == "" {
487				printLine(w, sevFail, hostName, fmt.Sprintf("native: PowerShell check failed (%v)", err))
488				r.Fail++
489				return
490			}
491			printLine(w, sevOK, hostName, fmt.Sprintf("native: PowerShell %s", out))
492		default:
493			printLine(w, sevWarn, hostName, fmt.Sprintf("native: unknown os %q", h.OS))
494			r.Warn++
495		}
496	}
