498	func hasAgenticRunners(runners []config.RunnerConfig, hostName string) bool {
499		for _, rc := range runners {
500			if rc.Host != hostName {
501				continue
502			}
503			if rc.IsAgentic() {
504				return true
505			}
506			// Native Linux setups use mode: native + labels including agentic (no profile).
507			// Legacy configs may still use the gh-aw label name.
508			for _, l := range rc.Labels {
509				if isAgenticRunnerLabel(l) {
510					return true
511				}
512			}
513		}
514		return false
515	}
516	
517	func isAgenticRunnerLabel(l string) bool {
518		s := strings.TrimSpace(l)
519		return strings.EqualFold(s, "agentic") || strings.EqualFold(s, "gh-aw")
520	}
