522	// checkAgenticPrereqs verifies host prerequisites specific to GitHub Agentic Workflows:
523	// port 80 availability (MCP gateway), iptables (AWF firewall), sudo access, and runner container tools.
524	func checkAgenticPrereqs(w io.Writer, hostName string, h *host.Host, runners []config.RunnerConfig, r *Result) {
525		if h.OS == "linux" || h.OS == "darwin" {
526			out, err := h.Run("ss -tlnp 2>/dev/null | grep -q ':80 ' && echo in-use || echo free")
527			if err == nil {
528				status := strings.TrimSpace(out)
529				if status == "in-use" {
530					printLine(w, sevWarn, hostName, "agentic: port 80 is in use; Agentic Workflows MCP gateway needs port 80 free on the host network")
531					r.Warn++
532				} else {
533					printLine(w, sevOK, hostName, "agentic: port 80 is free (MCP gateway)")
534				}
535			}
536		}
537	
538		if h.OS == "linux" {
539			out, err := h.Run("command -v iptables >/dev/null 2>&1 && echo yes || echo no")
540			if err == nil && strings.TrimSpace(out) == "yes" {
541				printLine(w, sevOK, hostName, "agentic: iptables available (AWF firewall)")
542			} else {
543				printLine(w, sevWarn, hostName, "agentic: iptables not found; AWF sandbox may fail (install iptables or ensure it is on PATH)")
544				r.Warn++
545			}
546	
547			// Check Docker daemon iptables setting (daemon.json absence means default iptables=true)
548			out, err = h.Run("cat /etc/docker/daemon.json")
549			if err == nil && strings.Contains(out, `"iptables": false`) {
550				printLine(w, sevWarn, hostName, "agentic: Docker iptables is disabled; AWF requires iptables integration")
551				r.Warn++
552			}
553	
554			// Check if DOCKER-USER chain is modifiable (try appending a RETURN rule)
555			out, err = h.Run("sudo iptables -A DOCKER-USER -j RETURN")
556			if err == nil {
557				// Rule added successfully - remove the test rule
558				h.Run("sudo iptables -D DOCKER-USER -j RETURN")
559				printLine(w, sevOK, hostName, "agentic: DOCKER-USER chain exists and is modifiable")
560			} else {
561				// Check if error indicates chain doesn't exist vs. permission denied
562				errOut, _ := h.Run("sudo iptables -L DOCKER-USER -n")
563				if errOut != "" && strings.Contains(errOut, "Chain doesn't exist") {
564					printLine(w, sevWarn, hostName, "agentic: DOCKER-USER chain missing; Docker iptables may be disabled")
565				} else {
566					printLine(w, sevWarn, hostName, "agentic: DOCKER-USER chain not modifiable; sudo may be needed for AWF")
567				}
568				r.Warn++
569			}
570	
571			// Check Docker's iptables filter chain list (look for DOCKER chain)
572			out, err = h.Run("sudo iptables -L -n")
573			if err == nil && strings.Contains(out, "DOCKER") {
574				printLine(w, sevOK, hostName, "agentic: Docker iptables rules present")
575			} else {
576				printLine(w, sevWarn, hostName, "agentic: No Docker iptables rules found; Docker may not be managing iptables")
577				r.Warn++
578			}
579	
580			uid, err := h.Run("id -u")
581			if err == nil && strings.TrimSpace(uid) != "0" {
582				out, err := h.Run("sudo -n true 2>/dev/null && echo ok || echo no")
583				if err != nil || strings.TrimSpace(out) != "ok" {
584					printLine(w, sevWarn, hostName, "agentic: passwordless sudo not available; AWF requires sudo for iptables/firewall setup")
585					r.Warn++
586				} else {
587					printLine(w, sevOK, hostName, "agentic: sudo available for AWF firewall setup")
588				}
589			}
590	
591			// Check if iptables and docker-compose are installed in running agentic runner containers
592			for _, rc := range runners {
593				if rc.Host != hostName || !rc.IsAgentic() {
594					continue
595				}
596				for _, inst := range rc.InstanceNames() {
597					cname := runner.ContainerName(inst)
598					running, rerr := h.Run(fmt.Sprintf("docker inspect -f '{{.State.Running}}' %s 2>/dev/null", cname))
599					if rerr != nil || strings.TrimSpace(running) != "true" {
600						continue
601					}
602					// Check iptables in container
603					out, ierr := h.Run(fmt.Sprintf("docker exec %s which iptables 2>/dev/null", cname))
604					if ierr != nil || strings.TrimSpace(out) == "" {
605						printLine(w, sevWarn, hostName, fmt.Sprintf("agentic: %s missing iptables (needed for AWF firewall)", cname))
606						r.Warn++
607					}
608					// Check docker compose v2 plugin in container
609					out, cerr := h.Run(fmt.Sprintf("docker exec %s docker compose version 2>&1", cname))
610					if cerr != nil || !strings.Contains(out, "Docker Compose") {
611						printLine(w, sevWarn, hostName, fmt.Sprintf("agentic: %s missing docker compose plugin (needed for AWF sidecars)", cname))
612						r.Warn++
613					}
614					// Only check first running instance per runner config; if we get here, tools are present
615					printLine(w, sevOK, hostName, fmt.Sprintf("agentic: %s has iptables and docker compose plugin (AWF tools)", cname))
616					break
617				}
618			}
619		}
620	}
621	
622	func checkLinuxSudo(w io.Writer, hostName string, h *host.Host, r *Result) {
623		uid, err := h.Run(`id -u`)
624		if err != nil {
625			printLine(w, sevWarn, hostName, fmt.Sprintf("linux: could not check uid: %v", err))
626			r.Warn++
627			return
628		}
629		if strings.TrimSpace(uid) == "0" {
630			return
631		}
632		out, err := h.Run(`sudo -n true 2>/dev/null && echo ok || echo no`)
633		out = strings.TrimSpace(out)
634		if err != nil || out != "ok" {
635			printLine(w, sevWarn, hostName, "linux: passwordless sudo not available; gh sr setup/update may fail for package installs or Docker install")
636			r.Warn++
637			return
638		}
639		printLine(w, sevOK, hostName, "linux: non-root user has passwordless sudo")
640	}
