101	// DefaultLabels generates standard GitHub Actions labels based on mode, host OS, and arch.
102	// Docker-mode runners always report as Linux regardless of host OS.
103	func DefaultLabels(mode, hostOS, arch string) []string {
104		labels := []string{"self-hosted"}
105	
106		osLabel := ""
107		switch mode {
108		case "docker":
109			osLabel = "Linux"
110		default:
111			switch hostOS {
112			case "linux":
113				osLabel = "Linux"
114			case "darwin":
115				osLabel = "macOS"
