119		}
120		if osLabel != "" {
121			labels = append(labels, osLabel)
122		}
123	
124		archLabel := ""
125		switch arch {
126		case "amd64":
127			archLabel = "X64"
128		case "arm64":
129			archLabel = "ARM64"
