138	// EffectiveLabels returns the runner's labels, auto-generating them from host info if empty.
139	// Agentic-profile runners automatically get an "agentic" label appended.
140	func (rc *RunnerConfig) EffectiveLabels(hostOS, arch string) []string {
141		var labels []string
142		if len(rc.Labels) > 0 {
143			labels = rc.Labels
144		} else {
