163	func (rc *RunnerConfig) InstanceNames() []string {
164		count := rc.Count
165		if count < 1 {
166			count = 1
167		}
168		names := make([]string, count)
169		for i := range count {
170			names[i] = fmt.Sprintf("%s-%d", rc.Name, i+1)
171		}
