175	func Load(path string) (*Config, error) {
176		data, err := os.ReadFile(path)
177		if err != nil {
178			return nil, fmt.Errorf("reading config: %w", err)
179		}
180	
181		var cfg Config
182		if err := yaml.Unmarshal(data, &cfg); err != nil {
183			return nil, fmt.Errorf("parsing config: %w", err)
184		}
185	
186		cfg.resolveEnvRefs()
187		cfg.applyDefaults()
188	
189		if err := cfg.Validate(); err != nil {
190			return nil, err
191		}
192	
193		return &cfg, nil
194	}
