200	func resolveEnv(val string) string {
201		if strings.HasPrefix(val, "env:") {
202			envVar := strings.TrimPrefix(val, "env:")
203			return os.Getenv(envVar)
204		}
205		return val
206	}
207	
208	func normalizeArch(goarch string) string {
209		switch goarch {
210		case "amd64", "arm64":
211			return goarch
212		default:
213			return goarch
214		}
215	}
216	
217	func (c *Config) applyDefaults() {
218		for name, h := range c.Hosts {
219			if IsLocalAddr(h.Addr) {
220				if h.OS == "" {
221					h.OS = runtime.GOOS
222				}
223				if h.Arch == "" {
224					h.Arch = normalizeArch(runtime.GOARCH)
225				}
226				c.Hosts[name] = h
227			}
228		}
229		for i := range c.Runners {
230			if c.Runners[i].Count < 1 {
231				c.Runners[i].Count = 1
232			}
233			c.Runners[i].applyAgenticDefaults()
234		}
235	}
236	
237	// applyAgenticDefaults fills in the Docker configuration implied by profile: agentic.
238	func (rc *RunnerConfig) applyAgenticDefaults() {
239		if !rc.IsAgentic() {
240			return
241		}
242		if rc.Mode == "" {
243			rc.Mode = "docker"
244		}
245		if rc.DockerNetworkMode == "" {
246			rc.DockerNetworkMode = "host"
247		}
248		if !hasCapability(rc.DockerCapAdd, "NET_ADMIN") {
249			rc.DockerCapAdd = append(rc.DockerCapAdd, "NET_ADMIN")
250		}
251		// Verify iptables and docker compose plugin are available for Agent Workflow Firewall (awf).
252		// The agentic runner image (ghcr.io/an-lee/agentic-runner) already includes these tools;
253		// this is a lightweight check that always succeeds (|| true) in case the image is updated
254		// and we need to verify on a running container.
255		// Only add the default if the user hasn't specified a custom pre_setup script.
256		if rc.DockerPreSetup == "" {
257			rc.DockerPreSetup = "command -v iptables >/dev/null 2>&1 && docker compose version >/dev/null 2>&1 || true"
258		}
259	}
