270	func (c *Config) Validate() error {
271		if c.GitHub.PAT != "" {
272			return fmt.Errorf("github.pat is no longer supported; remove it from runners.yml and authenticate with `gh auth login`")
273		}
274	
275		if len(c.Hosts) == 0 {
276			return fmt.Errorf("at least one host must be defined")
277		}
278	
279		for name, h := range c.Hosts {
280			if h.Addr == "" {
281				return fmt.Errorf("host %q: addr is required (use \"local\" for the current machine)", name)
282			}
283			// os and arch may be empty for remote hosts -- they are auto-detected over SSH before operations.
284			if h.OS != "" {
285				switch h.OS {
286				case "linux", "darwin", "windows":
287				default:
288					return fmt.Errorf("host %q: os must be linux, darwin, or windows (got %q)", name, h.OS)
289				}
290			}
291			if h.Arch != "" {
292				switch h.Arch {
293				case "amd64", "arm64":
294				default:
295					return fmt.Errorf("host %q: arch must be amd64 or arm64 (got %q)", name, h.Arch)
296				}
297			}
298			if h.WindowsPS != "" {
299				if h.OS != "" && h.OS != "windows" {
300					return fmt.Errorf("host %q: windows_ps is only valid when os is windows", name)
301				}
302				switch strings.ToLower(strings.TrimSpace(h.WindowsPS)) {
303				case "powershell", "pwsh":
304				default:
305					return fmt.Errorf("host %q: windows_ps must be powershell or pwsh (got %q)", name, h.WindowsPS)
306				}
307			}
308			if h.DockerSocket != "" {
309				if h.OS != "" && h.OS != "linux" && h.OS != "darwin" {
310					return fmt.Errorf("host %q: docker_socket is only supported on Linux and macOS hosts", name)
311				}
312				if !strings.HasPrefix(h.DockerSocket, "/") {
313					return fmt.Errorf("host %q: docker_socket must be an absolute path (got %q)", name, h.DockerSocket)
314				}
315			}
316		}
317	
318		if len(c.Runners) == 0 {
319			return fmt.Errorf("at least one runner must be defined")
320		}
321	
322		for _, r := range c.Runners {
323			if r.Name == "" {
324				return fmt.Errorf("runner name is required")
325			}
326			if r.Repo == "" && r.Org == "" {
327				return fmt.Errorf("runner %q: repo or org is required", r.Name)
328			}
329			if r.Repo != "" && r.Org != "" {
330				return fmt.Errorf("runner %q: specify repo or org, not both", r.Name)
331			}
332			if r.Group != "" && r.Org == "" {
333				return fmt.Errorf("runner %q: group requires org (runner groups are organization-level)", r.Name)
334			}
335			if r.Host == "" {
336				return fmt.Errorf("runner %q: host is required", r.Name)
337			}
338			hcfg, ok := c.Hosts[r.Host]
339			if !ok {
340				return fmt.Errorf("runner %q: host %q not found in hosts", r.Name, r.Host)
341			}
342			if r.Profile != "" && !strings.EqualFold(r.Profile, "agentic") {
343				return fmt.Errorf("runner %q: profile must be 'agentic' (got %q)", r.Name, r.Profile)
344			}
345			if r.IsAgentic() && r.Mode == "native" {
346				return fmt.Errorf("runner %q: profile 'agentic' requires docker mode (AWF sandbox needs Docker)", r.Name)
347			}
348			if r.Mode != "" && r.Mode != "docker" && r.Mode != "native" {
349				return fmt.Errorf("runner %q: mode must be 'docker' or 'native' (got %q)", r.Name, r.Mode)
350			}
351			netMode := strings.ToLower(strings.TrimSpace(r.DockerNetworkMode))
352			if netMode != "" && netMode != "bridge" && netMode != "host" {
353				return fmt.Errorf("runner %q: docker_network_mode must be 'bridge' or 'host' (got %q)", r.Name, r.DockerNetworkMode)
354			}
355			if netMode != "" {
356				if r.EffectiveMode(hcfg.OS) != "docker" {
357					return fmt.Errorf("runner %q: docker_network_mode applies only when mode is docker", r.Name)
358				}
359			}
360			if err := validateDockerCapAdd(&r, hcfg.OS); err != nil {
361				return err
362			}
363		}
364	
365		return nil
366	}
367	
368	func validateDockerCapAdd(r *RunnerConfig, hostOS string) error {
369		if len(r.DockerCapAdd) == 0 {
370			return nil
371		}
372		if r.EffectiveMode(hostOS) != "docker" {
373			return fmt.Errorf("runner %q: docker_cap_add applies only when mode is docker", r.Name)
374		}
375		for _, cap := range r.DockerCapAdd {
376			c := strings.TrimSpace(cap)
377			if c == "" {
378				return fmt.Errorf("runner %q: docker_cap_add contains an empty entry", r.Name)
379			}
380			if c != cap {
381				return fmt.Errorf("runner %q: docker_cap_add entries must not have leading or trailing spaces (got %q)", r.Name, cap)
382			}
383			for _, ch := range c {
384				isLetter := (ch >= 'a' && ch <= 'z') || (ch >= 'A' && ch <= 'Z')
385				isDigit := ch >= '0' && ch <= '9'
386				if !isLetter && !isDigit && ch != '_' {
387					return fmt.Errorf("runner %q: docker_cap_add invalid capability name %q (use letters, digits, underscore only)", r.Name, c)
388				}
389			}
390		}
391		return nil
392	}
393	
394	// NeedsDetection reports whether any host is missing os or arch (and is not local).
395	func (c *Config) NeedsDetection() bool {
396		for _, h := range c.Hosts {
397			if !IsLocalAddr(h.Addr) && (h.OS == "" || h.Arch == "") {
398				return true
399			}
400		}
401		return false
402	}
403	
404	func (c *Config) RunnersForHost(hostName string) []RunnerConfig {
405		var result []RunnerConfig
406		for _, r := range c.Runners {
407			if r.Host == hostName {
408				result = append(result, r)
409			}
410		}
