423	
424	func (c *Config) UniqueRepos() []string {
425		seen := map[string]bool{}
426		var repos []string
427		for _, r := range c.Runners {
428			if r.Repo == "" {
429				continue
430			}
431			if !seen[r.Repo] {
432				seen[r.Repo] = true
433				repos = append(repos, r.Repo)
434			}
435		}
436		return repos
437	}
438	
439	func (c *Config) UniqueOrgs() []string {
440		seen := map[string]bool{}
441		var orgs []string
442		for _, r := range c.Runners {
443			if r.Org == "" {
444				continue
445			}
446			if !seen[r.Org] {
447				seen[r.Org] = true
448				orgs = append(orgs, r.Org)
449			}
450		}
451		return orgs
452	}
453	
454	func (c *Config) FindRunner(name string) (*RunnerConfig, bool) {
455		for i := range c.Runners {
456			if c.Runners[i].Name == name {
457				return &c.Runners[i], true
458			}
459			for _, inst := range c.Runners[i].InstanceNames() {
460				if inst == name {
461					return &c.Runners[i], true
462				}
463			}
464		}
465		return nil, false
466	}
467	
468	// ResolveRunnerInstance maps a CLI argument (base name or instance) to the instance directory name (e.g. myapp-1).
469	func (rc *RunnerConfig) ResolveRunnerInstance(nameArg string) (string, error) {
470		for _, inst := range rc.InstanceNames() {
471			if inst == nameArg {
472				return inst, nil
473			}
474		}
475		if rc.Name == nameArg {
476			names := rc.InstanceNames()
477			if len(names) != 1 {
478				return "", fmt.Errorf("runner %q has %d instances; specify one of: %s", rc.Name, len(names), strings.Join(names, ", "))
479			}
480			return names[0], nil
481		}
482		return "", fmt.Errorf("runner %q: %q is not a valid name or instance", rc.Name, nameArg)
483	}
484	
485	// FindRunnerForLogs resolves a runner by base or instance name. If hostFilter is non-empty, only that host's runner block matches.
486	// Returns an error when nothing matches or when multiple hosts match the same name without a host filter.
487	func (c *Config) FindRunnerForLogs(nameArg, hostFilter string) (*RunnerConfig, error) {
488		var matches []*RunnerConfig
489		seen := map[*RunnerConfig]bool{}
490		for i := range c.Runners {
491			r := &c.Runners[i]
492			if hostFilter != "" && r.Host != hostFilter {
493				continue
494			}
495			matched := false
496			if r.Name == nameArg {
497				matched = true
498			} else {
499				for _, inst := range r.InstanceNames() {
500					if inst == nameArg {
501						matched = true
502						break
503					}
504				}
505			}
506			if matched && !seen[r] {
507				seen[r] = true
508				matches = append(matches, r)
509			}
510		}
511		if len(matches) == 0 {
512			if hostFilter != "" {
513				return nil, fmt.Errorf("runner %q not found for host %q", nameArg, hostFilter)
514			}
515			return nil, fmt.Errorf("runner %q not found in config", nameArg)
516		}
517		if len(matches) > 1 {
518			hosts := make([]string, 0, len(matches))
519			for _, r := range matches {
520				hosts = append(hosts, r.Host)
