1	package main
2	
3	import (
4		"bufio"
5		"fmt"
6		"io"
7		"os"
8		"path/filepath"
9		"strings"
10	
11		"github.com/spf13/cobra"
12		"golang.org/x/term"
13	
14		"github.com/an-lee/gh-sr/internal/config"
15		"github.com/an-lee/gh-sr/internal/doctor"
16		"github.com/an-lee/gh-sr/internal/editor"
17		"github.com/an-lee/gh-sr/internal/ops"
18		"github.com/an-lee/gh-sr/internal/runner"
19		"github.com/an-lee/gh-sr/internal/tui"
20	)
21	
22	var version = "dev"
23	
24	var (
25		cfgFile    string
26		filterHost string
27		filterRepo string
28	)
29	
30	// linuxSetupPrivilegesHelp is appended to root/setup/update Long text (non-interactive SSH + sudo behavior on Linux).
31	const linuxSetupPrivilegesHelp = `
32	
33	Linux hosts: gh sr setup and update may run package installs and similar steps on the remote host. For a non-root
34	SSH user, gh sr uses sudo when the sudo binary exists on the remote PATH; SSH is non-interactive, so passwordless
35	sudo (or SSH as root) is usually required for those steps to succeed. For docker mode without Docker installed,
36	install Docker yourself or ensure sudo works; for native mode, pre-install curl/tar and runner OS dependencies
37	if you cannot use sudo. See the README section "Linux SSH user and privileges".
38	
39	Docker mode on Linux requires the SSH user to run docker without sudo. If docker info fails with permission
40	denied on the socket, on the host (as root) run: sudo usermod -aG docker <ssh-user>, then reconnect SSH or run
41	newgrp docker so group membership applies.`
42	
43	// serviceLongHelp documents autostart behavior for the service subcommands.
44	const serviceLongHelp = `
45	
46	Native runners do not survive host reboot until OS autostart is installed (gh sr service install). After install,
47	gh sr up and gh sr down start and stop the same supervisor (systemd, launchd, or a Windows scheduled task).
48	
49	Linux user units (default) require loginctl enable-linger <user> on many headless servers so systemd --user
50	starts at boot without an interactive login. Use --system on Linux only for a system-wide unit in
51	/etc/systemd/system (needs passwordless sudo or root SSH).
52	
53	Docker mode uses the container restart policy unless-stopped; gh sr service install skips docker runners.`
54	
55	func main() {
56		root := &cobra.Command{
57			Use:   "sr",
58			Short: "Manage self-hosted GitHub Actions runners across multiple hosts",
59			Long: `Self-hosted runner manager for GitHub (gh sr) manages self-hosted GitHub Actions runners on any combination
60	of Linux, macOS, and Windows hosts — all from your laptop over SSH.
61	
62	Define your hosts and runners in ~/.gh-sr/runners.yml (or set GH_SR_CONFIG / --config),
63	then use unified commands to setup, start, stop, and monitor everything.
64	
65	With no subcommand, gh sr opens the interactive dashboard on a terminal; use gh sr --help for all commands.` + linuxSetupPrivilegesHelp,
66			SilenceUsage: true,
67			RunE: func(cmd *cobra.Command, args []string) error {
68				if len(args) > 0 {
69					return fmt.Errorf("unknown argument %q — use a subcommand or gh sr --help", args[0])
70				}
71				return runDashboard()
72			},
73		}
74	
75		root.PersistentFlags().StringVarP(&cfgFile, "config", "c", "", "config file path (empty = auto; use \"gh sr config path\" to print the resolved file)")
76		root.PersistentFlags().StringVar(&filterHost, "host", "", "filter by host name")
77		root.PersistentFlags().StringVar(&filterRepo, "repo", "", "filter by repo (owner/repo)")
78	
79		root.AddCommand(
80			initCmd(),
81			addCmd(),
82			doctorCmd(),
83			setupCmd(),
84			upCmd(),
85			downCmd(),
86			restartCmd(),
87			statusCmd(),
88			logsCmd(),
89			cleanupCmd(),
90			updateCmd(),
91			serviceCmd(),
92			configCmd(),
93			dashboardCmd(),
94			hostsCmd(),
95			versionCmd(),
96		)
97	
98		if err := root.Execute(); err != nil {
99			os.Exit(1)
100		}
101	}
102	
103	func runDashboard() error {
104		if !term.IsTerminal(int(os.Stdout.Fd())) {
105			fmt.Fprintln(os.Stderr, tui.NonTTYHint)
106			return nil
107		}
108		cfg, err := loadConfig()
109		if err != nil {
110			return err
111		}
112		cfgPath, err := config.ResolveConfigPath(cfgFile)
113		if err != nil {
114			return err
115		}
