203	func runQuickInit(runnersPath string, force bool) error {
204		scanner := bufio.NewScanner(os.Stdin)
205		prompt := func(label, defaultVal string) string {
206			if defaultVal != "" {
207				fmt.Printf("%s [%s]: ", label, defaultVal)
208			} else {
209				fmt.Printf("%s: ", label)
210			}
211			if scanner.Scan() {
212				v := strings.TrimSpace(scanner.Text())
213				if v != "" {
214					return v
215				}
216			}
217			return defaultVal
218		}
219	
220		fmt.Println("=== gh sr quick setup ===")
221		fmt.Println("This will create a working config. OS, arch, mode, and labels are all auto-detected.")
222		fmt.Println()
223	
224		repo := prompt("GitHub repo (owner/repo)", "")
225		if repo == "" {
226			return fmt.Errorf("repo is required")
227		}
228		if !strings.Contains(repo, "/") {
229			return fmt.Errorf("repo must be in owner/repo format")
230		}
231	
232		addr := prompt("SSH address of runner host (user@host, or 'local' for this machine)", "local")
233	
234		hostName := "runner-host"
235		if config.IsLocalAddr(addr) {
236			hostName = "local"
237		} else {
238			parts := strings.SplitN(addr, "@", 2)
239			if len(parts) == 2 {
240				h := strings.Split(parts[1], ":")[0]
241				h = strings.ReplaceAll(h, ".", "-")
242				if h != "" {
243					hostName = h
244				}
245			}
246		}
247	
248		baseName := strings.ReplaceAll(strings.Split(repo, "/")[1], ".", "-")
249		runnerName := baseName + "-" + hostName
250	
251		countStr := prompt("Number of runner instances", "1")
252		count := 1
253		if _, err := fmt.Sscanf(countStr, "%d", &count); err != nil || count < 1 {
254			count = 1
255		}
256	
257		agenticAnswer := prompt("Use GitHub Agentic Workflows profile? (y/n)", "n")
258		agentic := strings.ToLower(strings.TrimSpace(agenticAnswer)) == "y"
259	
260		var profileLine string
261		if agentic {
262			profileLine = "\n    profile: agentic"
263		}
264	
265		seed := fmt.Sprintf(`github: {}
266	hosts:
267	  %s:
268	    addr: %s
269	runners:
270	  - name: %s
271	    repo: %s
272	    host: %s
273	    count: %d%s
274	`, hostName, addr, runnerName, repo, hostName, count, profileLine)
275	
276		if _, err := os.Stat(runnersPath); err == nil && !force {
277			fmt.Printf("\n%s already exists. Overwrite? [y/N]: ", runnersPath)
278			if scanner.Scan() {
279				if strings.ToLower(strings.TrimSpace(scanner.Text())) != "y" {
280					fmt.Println("Aborted.")
281					return nil
282				}
283			}
284		}
285	
286		if err := os.WriteFile(runnersPath, []byte(seed), 0o600); err != nil {
287			return err
288		}
289		fmt.Printf("\nWrote %s\n", runnersPath)
290	
291		// Validate the generated config loads.
292		if _, err := config.Load(runnersPath); err != nil {
293			return fmt.Errorf("generated config is invalid: %w", err)
294		}
295	
296		fmt.Println()
297		fmt.Println("Config generated! Summary:")
298		fmt.Printf("  Host:   %s (%s)\n", hostName, addr)
299		fmt.Printf("  Runner: %s -> %s (x%d)\n", runnerName, repo, count)
300		if agentic {
301			fmt.Println("  Profile: agentic (docker, host network, NET_ADMIN, agentic label)")
302		} else {
303			fmt.Println("  Mode:   auto-detected at runtime")
304		}
305		fmt.Println("  Labels: auto-generated from host os/arch")
306		fmt.Println()
307		fmt.Println("Next steps:")
308		fmt.Println("  gh sr doctor   # verify config, GitHub access, and host connectivity")
309		fmt.Println("  gh sr up       # setup + start runners (all in one)")
310		fmt.Println()
311		fmt.Println("Authentication: run `gh auth login`.")
312	
313		return nil
314	}
