12	// ServiceInstall installs OS-level autostart for native runners (systemd, LaunchAgent, or scheduled task).
13	func ServiceInstall(w io.Writer, cfg *config.Config, filterHost, filterRepo string, nameArgs []string, system bool) error {
14		if err := ResolveHostInfo(w, cfg); err != nil {
15			return err
16		}
17		if err := ResolveModes(w, cfg); err != nil {
18			return err
19		}
20		runners := config.FilterRunners(cfg, filterHost, filterRepo, nameArgs)
21		for _, rc := range runners {
22			hcfg := cfg.Hosts[rc.Host]
23			mode := rc.EffectiveMode(hcfg.OS)
24			if system && hcfg.OS != "linux" {
25				return fmt.Errorf("--system applies only to Linux hosts (host %q is %s)", rc.Host, hcfg.OS)
26			}
27			if config.IsLocalAddr(hcfg.Addr) {
