	if err != nil || inst != "dup-1" {
		t.Fatalf("ResolveRunnerInstance dup-1: %v %q", err, inst)
	}
	inst, err = rc.ResolveRunnerInstance("dup")
	if err != nil || inst != "dup-1" {
