    addr: a@b
    os: linux
    arch: amd64
runners:
  - name: aw
    repo: o/r
    host: h1
    profile: agentic
`
	if err := os.WriteFile(path, []byte(content), 0o600); err != nil {
		t.Fatal(err)
	}
	cfg, err := Load(path)
	if err != nil {
		t.Fatal(err)
